{ === GC: mark/sweep over per-type alloc lists ===
  Single procedure to stay within p24p's MAX_PROCS budget. Mutual
  recursion across the four record types is handled by an iterative
  fixed-point: walk each alloc list repeatedly, propagating mark bits
  to referents, until no new marks. O(N*depth); for the saga's #28
  fixture this is well under a second. }
procedure gc_collect;
var
  ce: PExpr; cp: PPat; cv: PVal; cn: PEnv;
  pe: PExpr; pp: PPat; pv: PVal; pn: PEnv;
  ne: PExpr; np: PPat; nv: PVal; nn: PEnv;
  changed: boolean;
begin
  { Pass 1: clear all mark bits }
  ce := expr_alloc_head; while ce <> nil do begin ce^.mark_bit := 0; ce := ce^.next_alloc end;
  cp := pat_alloc_head;  while cp <> nil do begin cp^.mark_bit := 0; cp := cp^.next_alloc end;
  cv := val_alloc_head;  while cv <> nil do begin cv^.mark_bit := 0; cv := cv^.next_alloc end;
  cn := env_alloc_head;  while cn <> nil do begin cn^.mark_bit := 0; cn := cn^.next_alloc end;

  { Pass 2: prime mark from top_env (the sole root) }
  cn := top_env;
  while cn <> nil do begin cn^.mark_bit := 1; cn := cn^.next end;

  { Pass 3: iterative fixed-point — walk alloc lists, propagate marks
    to referents based on per-kind field semantics, until stable. }
  changed := true;
  while changed do begin
    changed := false;

    { Mark referents of marked Env entries: val + next }
    cn := env_alloc_head;
    while cn <> nil do begin
      if cn^.mark_bit = 1 then begin
        if (cn^.val <> nil) and (cn^.val^.mark_bit = 0) then begin cn^.val^.mark_bit := 1; changed := true end;
        if (cn^.next <> nil) and (cn^.next^.mark_bit = 0) then begin cn^.next^.mark_bit := 1; changed := true end
      end;
      cn := cn^.next_alloc
